var CRMInvoicePage = ( function($) {

    CRMInvoicePage = function(options) {
        var that = this;

        // DOM
        that.$wrapper = options["$wrapper"];

        // VARS
        that.invoice_id = options["invoice_id"];
        that.recurrent_id = options["recurrent_id"];
        that.locales = options["locales"];

        // DYNAMIC VARS

        // INIT
        that.initClass();
    };

    CRMInvoicePage.prototype.initClass = function() {
        var that = this;
        //
        that.initChangeState();
        //
        that.initDelete();
        //
        that.initRecurrent();
        //
        that.initRefund();
        //
        that.initRestore();
        // set active in sidebar
        setTimeout( function() {
            $(document).trigger("viewInvoice", that.invoice_id);
        }, 100);

        that.$wrapper.data("page", that);

        $('.js-action-link').one("click", function (e) {
            spinnerView($(this)).show();
        })
    };

    CRMInvoicePage.prototype.initChangeState = function() {
        var that = this,
            $wrapper = that.$wrapper,
            invoice_id = that.invoice_id,
            is_locked = false;

        $wrapper.on("click", ".js-change-state", function(event) {
            event.preventDefault();
            var action = $(this).data("action");
            if (action) { submit(action, $(this)); }
        });

        function submit(action, $button) {
            if (!is_locked) {
                is_locked = true;

                var href = "?module=invoice&action=handleTransaction",
                    data = {
                        invoice_id: invoice_id,
                        action: action
                    };

                const spinner = spinnerView($button);
                spinner.show();
                $.post(href, data, function(response) {
                    if (response.status === "ok") {
                        const iframe = getIframeIfExists();
                        if (iframe) {
                            window.parent.iframe_invoice_is_saved = true;
                            iframe.contentWindow.location.reload();
                        } else {
                            updateInvoiceAtSidebar(that.invoice_id, (action === "delete" ? "" : response.data.html));
                            var redirect_uri = $.crm.app_url + "invoice/" + that.invoice_id + "/";
                            that.load(redirect_uri);
                        }
                    } else {
                        alert(response.errors);
                    }
                }, "json").always( function() {
                    spinner.hide();
                    is_locked = false;
                });
            }
        }
    };

    CRMInvoicePage.prototype.initDelete = function() {
        var that = this,
            is_locked = false;

        that.$wrapper.on("click", ".js-delete-invoice", function(event) {
            event.preventDefault();

            $.waDialog.confirm({
                title: that.locales["delete_confirm_title"],
                text: that.locales["delete_confirm_text"],
                success_button_title: that.locales["delete_confirm_button"],
                success_button_class: 'danger',
                cancel_button_title: that.locales["delete_confirm_cancel_button"],
                cancel_button_class: 'light-gray',
                onSuccess: deleteInvoice
            });
        });

        function deleteInvoice(dialog) {
            if (!is_locked) {
                is_locked = true;

                var href = "?module=invoice&action=handleTransaction",
                    data = {
                        invoice_id: that.invoice_id,
                        action: "delete"
                    };

                const spinner = spinnerView(dialog.$body.find('.js-success-action'));
                spinner.show();
                $.post(href, data, function(response) {
                    if (response.status === "ok") {
                        var content_uri = $.crm.app_url + "invoice/";
                        const iframe = getIframeIfExists();
                        if (iframe) {
                            iframe.dispatchEvent(new CustomEvent('close', { detail: { action: 'refresh' } }));
                        } else {
                            $.crm.content.load(content_uri);
                        }
                    }
                }, "json").always( function() {
                    spinner.hide();
                    is_locked = false;
                });
            }
        }
    };

    CRMInvoicePage.prototype.initRecurrent = function() {
        var that = this,
            is_locked = false;

        const $dropdown = that.$wrapper.find("#dropdown-recurrent");
        const $button = $dropdown.find(".dropdown-toggle");

        $dropdown.waDropdown({
            hover: true,
        });

        $dropdown.find(".js-recurrent-set").on("click", function(event) {
            event.preventDefault();
            if (is_locked) {
                return;
            }
            is_locked = true;
            const spinner = spinnerView($button, 0);
            spinner.show();

            const $item = $(event.target);
            const val = $(event.target).data("id");
            const href = $.crm.app_url + "?module=invoice&action=recurrentSave",
                data = {
                    recurrent_id: that.recurrent_id,
                    invoice_id: that.invoice_id,
                    interval_unit: val
                };
            $.post(href, data, function(response) {
                if (response.status === "ok") {
                    $dropdown.find(".js-recurrent-description").text(response.data.recurrent_description);
                    $dropdown.find(".selected").removeClass("selected");
                    $item.closest("li").addClass("selected");
                    $dropdown.find(".js-recurrent-none").closest("li").removeClass("disabled");
                } else {
                    showErrors(response.errors);
                }
            }, "json").always( function() {
                spinner.hide();
                is_locked = false;
            });
        });

        $dropdown.find(".js-recurrent-tune").on("click", function(event) {
            event.preventDefault();
            if (is_locked) {
                return;
            }
            is_locked = true;
            const spinner = spinnerView($button, 0);
            spinner.show();

            const href = $.crm.app_url + "?module=invoice&action=recurrentDialog&invoice_id=" + that.invoice_id;
            $.get(href, function(html) {
                $.waDialog({
                    html: html,
                });
            }).always( function() {
                spinner.hide();
                is_locked = false;
            });
        });

        $dropdown.find(".js-recurrent-none").on("click", function(event) {
            event.preventDefault();
            const $item = $(event.target);

            $.waDialog.confirm({
                title: that.locales["recurring_off_title"],
                text: that.locales["recurring_off_text"],
                success_button_title: that.locales["recurring_off_button"],
                success_button_class: 'danger',
                cancel_button_title: that.locales["recurring_off_cancel_button"],
                cancel_button_class: 'light-gray',
                onSuccess: function(dialog) {
                    const href = $.crm.app_url + "?module=invoice&action=recurrentDelete";
                    $.post(href, {
                        recurrent_id: that.recurrent_id,
                        invoice_id: that.invoice_id
                    }, function(response) {
                        if (response.status === "ok") {
                            $(".js-recurrent-description").text($item.data('description'));
                            $item.closest("ul.menu").find(".selected").removeClass("selected");
                            $item.closest("li").addClass("selected").addClass("disabled");
                        }
                    }, "json").always( function() {
                        //spinner.hide();
                        //is_locked = false;
                    });
                }
            });
        });
    };

    CRMInvoicePage.prototype.initRefund = function() {
        var that = this,
            is_locked = false;

        that.$wrapper.on("click", ".js-change-refund", function(event) {
            event.preventDefault();
            showDialog($(this));
        });

        function showDialog($button) {
            if (!is_locked) {
                is_locked = true;

                var href = $.crm.app_url + "?module=invoice&action=refundDialog",
                    data = {
                        invoice_id: that.invoice_id
                    };

                const spinner = spinnerView($button, 0);
                spinner.show();
                $.post(href, data, function(html) {
                    $.waDialog({
                        html: html,
                        options: {
                            onRefund: function(data) {
                                const iframe = getIframeIfExists();
                                if (iframe) {
                                    window.parent.iframe_invoice_is_saved = true;
                                    iframe.contentWindow.location.reload();
                                } else {
                                    updateInvoiceAtSidebar(that.invoice_id, data.html);
                                    that.reload();
                                }
                            }
                        }
                    });
                }).always( function() {
                    spinner.hide();
                    is_locked = false;
                });
            }
        }
    };

    CRMInvoicePage.prototype.initRestore = function() {
        var that = this,
            is_locked = false;

        that.$wrapper.on("click", ".js-restore-invoice", function(event) {
            event.preventDefault();
            restore($(this));
        });

        function restore($button) {
            if (!is_locked) {
                is_locked = true;

                var href = "?module=invoiceRestore",
                    data = {
                        id: that.invoice_id
                    };

                const spinner = spinnerView($button);
                spinner.show();
                $.post(href, data, function(response) {
                    if (response.status === "ok") {
                        const iframe = getIframeIfExists();
                        if (iframe) {
                            window.parent.iframe_invoice_is_saved = true;
                            iframe.contentWindow.location.reload();
                        } else {
                            updateInvoiceAtSidebar(that.invoice_id, response.data.html);
                            that.reload();
                        }
                    } else {
                        spinner.hide();
                        alert(response.errors);
                    }
                }, "json").always( function() {
                    is_locked = false;
                });
            }
        }

    };

    CRMInvoicePage.prototype.load = function(content_uri) {
        var that = this;

        var $link = $("<a />").addClass("js-disable-router").attr("href", content_uri).hide();
        that.$wrapper.append($link);
        $link.trigger("click");
    };

    CRMInvoicePage.prototype.reload = function() {
        var that = this;
        that.load(location.href);
    };

    return CRMInvoicePage;

    /**
     * @param {Number|String} invoice_id
     * @param {String} html
     * */
    function updateInvoiceAtSidebar(invoice_id, html) {
        if (!invoice_id) {
            return false;
        }

        var $selectedInvoice = $(".js-invoices-list .c-invoice[data-id=\"" + invoice_id + "\"]");
        if ($selectedInvoice.length) {
            if (html) {
                $selectedInvoice.replaceWith(html);
            } else {
                $selectedInvoice.remove();
            }
        }
    }

})(jQuery);

