var CRMInvoiceRefundDialog = ( function($) {

    CRMInvoiceRefundDialog = function(options) {
        var that = this;

        // DOM
        that.$wrapper = options["$wrapper"];
        that.$form = that.$wrapper.find("form");

        // VARS
        that.dialog = that.$wrapper.data("dialog");

        // DYNAMIC VARS

        // INIT
        that.initClass();
    };

    CRMInvoiceRefundDialog.prototype.initClass = function() {
        var that = this;

        that.initSubmit();
    };

    CRMInvoiceRefundDialog.prototype.initSubmit = function() {
        var that = this,
            $form = that.$form,
            is_locked = false;

        $form.on("submit", onSubmit);

        function onSubmit(event) {
            event.preventDefault();

            var formData = getData();

            if (formData.errors.length) {
                showErrors(formData.errors);
            } else {
                request(formData.data, $form.find('.js-submit-button'));
            }
        }

        function getData() {
            var result = {
                    data: [],
                    errors: []
                },
                data = $form.serializeArray();

            $.each(data, function(index, item) {
                result.data.push(item);
            });

            return result;
        }

        function showErrors(errors) {
            console.log(errors);
        }

        function request(data, $button) {
            if (!is_locked) {
                is_locked = true;
                var href = $.crm.app_url + "?module=invoice&action=handleTransaction";

                const spinner = spinnerView($button);
                spinner.show();
                $.post(href, data, function(response) {
                    if (response.status === "ok") {
                        that.dialog.options.onRefund(response.data);
                        that.dialog.close();
                    } else {
                        showErrors(response.errors);
                    }
                }, "json").always( function() {
                    spinner.hide();
                    is_locked = false;
                });
            }
        }
    };

    return CRMInvoiceRefundDialog;

})(jQuery);

function getIframeIfExists () {
    const iframe = new URLSearchParams(document.location.search).get('iframe');
    if (iframe && window.parent) {
        return window.parent.document.getElementById('iframe-invoice')
    }

    return null
}

function spinnerView ($button, timeout = 350) {
    const $loading = $('<span class="icon custom-mr-4 js-loading"><i class="fas fa-spinner wa-animation-spin"></i></span>');
    const $existsIcon = $button.find('.icon:not(.js-loading)')
    return {
        show: function () {
            if ($existsIcon) {
                $existsIcon.hide();
            }

            $button.prepend($loading);
            if ($button.prop("tagName") === "BUTTON") {
                $button.prop('disabled', true);
            }
        },
        hide: function () {
            setTimeout(() => {
                $button.removeAttr('disabled');
                $button.find('.js-loading').remove();
                if ($existsIcon) {
                    $existsIcon.show();
                }
            }, timeout)
        }
    }
}

var CrmInvoiceIframe = ( function($) {
    var CrmInvoiceIframe = function() {

        $('.js-cancel-button').one('click', function (e) {
            e.preventDefault();

            if ($(this).hasClass('js-disable-router')) {
                window.history.back();
            } else {
                const iframe = getIframeIfExists();
                if (iframe) {
                    iframe.dispatchEvent(new CustomEvent('close', {
                        detail: { action: window.parent.iframe_invoice_is_saved ? 'refresh' : null }
                    }));
                    delete window.parent.iframe_invoice_is_saved;
                }
            }
        })
    };

    return CrmInvoiceIframe;
})($);
