var CRMCallInitContactDialog = ( function($) {

    CRMCallInitContactDialog = function(options) {
        var that = this;

        // DOM
        that.$wrapper = options["$wrapper"];
        that.$footer = that.$wrapper.find('.js-dialog-footer');
        that.$form = that.$wrapper.find('form');
        that.$call_button = that.$form.find('.js-init-call');
        that.$content = that.$form.find('.js-content');
        that.$numbers_list = that.$form.find('.js-numbers-list');
        that.$plugin_id = that.$form.find('.js-plugin-id');

        // VARS
        that.dialog = that.$wrapper.data("dialog");
        that.call_id = 0;
        that.call_ready = options['call_ready'];
        that.locales = options['locales'];
        that.iframe = options["iframe"];

        // DYNAMIC VARS

        // INIT
        that.initClass();
    };

    CRMCallInitContactDialog.prototype.initClass = function() {
        var that = this;

        //
        if (that.call_ready === 'ready') {
            that.initCall();
        } else {
            that.selectExtensionNumber();
            that.submit();
        }

        if (that.iframe) {
            that.$wrapper.on('click', '.js-close-dialog', function(e){
                e.preventDefault();
                $('.dialog iframe', window.parent.document)[0].dispatchEvent(new Event('close'));
                
            })
        }
    };

    /**
     * Just selector
     */
    CRMCallInitContactDialog.prototype.selectExtensionNumber = function() {
        var that = this;

        that.$form.on('click', '.js-number-item', function () {
            var $item = $(this),
                plugin_id = $item.data('plugin-id');

            that.$plugin_id.val($.crm.escape(plugin_id));
            that.$call_button.prop('disabled', false);
        });
    };

    /**
     * Small validation of entered data.
     */
    CRMCallInitContactDialog.prototype.submit = function() {
        var that = this;

        that.$form.on('submit', function (e) {
            e.preventDefault();

            var plugin_id = that.$plugin_id.val();

            if (!plugin_id) {
                that.$numbers_list.addClass('shake animated');
                setTimeout(function(){
                    that.$numbers_list.removeClass('shake animated');
                },500);
                return false;
            }

            that.initCall();
        });
    };

    /**
     * The method sends a request to the plugin to start a new outgoing call.
     * Then a new call is made in CRM.
     */
    CRMCallInitContactDialog.prototype.initCall = function() {
        var that = this;

        var $loading = $('<span class="icon size-16 loading"><i class="fas fa-spinner fa-spin"></i></span>'),
            href = $.crm.app_url + "?module=call&action=initNew",
            data = that.$form.serializeArray();

        that.$call_button.prop('disabled', true);
        that.$footer.append($loading);

        $.post(href, data)
            .done(function(res){
                if (res.status === "ok") {
                    that.call_id = res.data.call_id;
                    that.callChecker();
                } else {
                    console.error(res);
                }
            })
            .fail(function () {
                that.iframe? $('.dialog iframe', window.parent.document)[0].dispatchEvent(new Event('close')) : that.dialog.close();
            })
            .always(function () {
                that.$call_button.prop('disabled', false);
                $loading.remove();
            });
    };

    /**
     * The method updates the call status every 2 seconds.
     */
    CRMCallInitContactDialog.prototype.callChecker = function() {
        var that = this,
            call_id = that.call_id,
            $close_button = '<input class="button js-close-dialog" type="submit" value="'+ that.locales['Close'] +'">',
            $status_pending = '<div class="c-call-pending">'+ that.locales['call_pending'] +'<span class="icon size-16 loading custom-pl-8"><i class="fas fa-spinner fa-spin"></i></span></div>',
            $status_connected = '<div style="color: #00ff00;">'+ that.locales['call_connected'] +'</div>',
            $status_finished = '<div style="color: #5159c3;">'+ that.locales['call_finished'] +'</div>';

        that.$content.html($status_pending);
        that.$footer.html($close_button);

        callCheck();
        var intervalID = setInterval(callCheck, 2000);

        function callCheck() {
            var href = $.crm.app_url + "?module=call&action=checkStatus",
                data = {id: call_id};

            $.post(href, data, function(res){
                try {
                    if (res.errors) {
                        clearInterval(intervalID);
                        that.$content.html($status_finished);
                        setTimeout(function () {
                            if (that.iframe) {
                                $('.dialog iframe', window.parent.document)[0].dispatchEvent(new Event('close'))
                            } 
                            else {
                                that.dialog.close();
                                $.crm.content.reload();
                            }

                        }, 3000);
                        console.log(res.errors.message);
                    }

                    if (res.data.status_id === "PENDING") {
                        that.$content.html($status_pending);
                    } else if (res.data.status_id === "CONNECTED") {
                        that.$content.html($status_connected);
                    } else {
                        that.$content.html($status_finished);
                        clearInterval(intervalID);
                        setTimeout(function () {
                            if (that.iframe) {
                                $('.dialog iframe', window.parent.document)[0].dispatchEvent(new Event('close'))
                            } 
                            else {
                                that.dialog.close();
                                $.crm.content.reload();
                            }
                        }, 3000);
                    }
                } catch (e) {
                    clearInterval(intervalID);
                    console.log('Error while updating call status');
                    console.log(e);
                }
            });
        }
    };

    return CRMCallInitContactDialog;

})(jQuery);
;
var CRMCallRedirectDialog = ( function($) {

    CRMCallRedirectDialog = function(options) {
        var that = this;

        // DOM
        that.$wrapper = options["$wrapper"];
        that.$form = that.$wrapper.find('form');
        that.$button = that.$form.find('.js-submit');
        that.$autocomplete = that.$form.find('.js-autocomplete');
        that.$other_radio = that.$form.find('.js-other-candidate');

        that.$number = that.$form.find('.js-number');

        // VARS

        // DYNAMIC VARS

        // INIT
        that.initClass();
    };

    CRMCallRedirectDialog.prototype.initClass = function() {
        var that = this;

        that.initAutocomplete();
        //
        that.initSelectCandidate();
        //
        that.initSubmit();
    };

    CRMCallRedirectDialog.prototype.initAutocomplete = function() {
        var that = this,
            $other_candidate = that.$form.find('.js-candidate'),
            $delete_candidate = $other_candidate.find('.js-delete-candidate');

        that.$autocomplete.autocomplete({
            source: $.crm.app_url + "?module=autocomplete&type=user&phonecomplete=true",
            appendTo: that.$autocomplete.parent(),
            minLength: 0,
            focus: function() {
                return false;
            },
            select: function(event, ui) {
                that.$number.val(ui.item.phone);
                $other_candidate.find('.js-label').html(ui.item.label);
                that.$autocomplete.css('display','none');
                $other_candidate.removeClass('hidden');
                return false;
            }
        }).data("ui-autocomplete")._renderItem = function(ul, item) {
            return $('<li class="ui-menu-item-html"><div>' + item.value + '</div></li>').appendTo(ul);
        };
        that.$autocomplete.on("focus", function(){
            $(this).data("uiAutocomplete").search( $(this).val() );
        });

        // Remove other candidate
        $delete_candidate.on('click', function () {
            that.$number.val("");
            $other_candidate.addClass('hidden');
            that.$autocomplete.val('').removeAttr('style').focus();
        });
    };

    CRMCallRedirectDialog.prototype.initSelectCandidate = function() {
        var that = this,
            $other_lbl = that.$form.find('.js-other-lbl'),
            $other_candidate = that.$form.find('.js-candidate'),
            $number_type = that.$form.find('.js-number-type');

        that.$form.on('change', ":radio[name='redirect[to]']", function () {
            // external number
            if (that.$other_radio.prop('checked')) {
                $number_type.val('external');
                that.$number.val("");
                that.$autocomplete.removeAttr('style').focus();
                $other_lbl.css('display', 'none');
            // interior number
            } else {
                $number_type.val('interior');
                that.$number.val($(this).val());
                that.$autocomplete.css('display', 'none');
                $other_candidate.addClass('hidden');
                that.$autocomplete.val('');
                $other_lbl.removeAttr('style');
            }

            that.$button.prop('disabled', false);
        });
    };

    CRMCallRedirectDialog.prototype.initSubmit = function() {
        var that = this,
            $name = that.$form.find('.js-field-name');

        that.$form.on('submit', function (e) {
            e.preventDefault();

            var call_id = that.$wrapper.find('.js-call-id').val(),
                number = that.$number.val();
            if (!$.trim(number)) {
                number = $.trim(that.$autocomplete.val());
            }

            if (!$.trim(number)) {
                $name.addClass('shake animated');
                setTimeout(function(){
                    $name.removeClass('shake animated');
                },500);

                return false;
            }

            submit();

            function submit() {
                var number_type = that.$form.find('.js-number-type').val(),
                    $footer = that.$wrapper.find('.js-dialog-footer'),
                    $loading = $('<span class="icon size-16 loading"><i class="fas fa-spinner fa-spin"></i></span>');

                that.$button.prop('disabled', true);
                $footer.append($loading);

                var href = $.crm.app_url+'?module=call&action=redirect',
                    data = { call_id: call_id, number_type: number_type, number: number };

                $.post(href, data, function (r) {
                    if (r.status === "ok") {
                        $footer.find('.svg-inline--fa.fa-spinner').removeClass('fa-spinner fa-spin').addClass('fa-check text-green');
                        that.$wrapper.hide();
                        setTimeout(function () {
                            $.crm.content.reload();
                        }, 2000);
                    }
                });
            }
        });
    };


    return CRMCallRedirectDialog;

})(jQuery);;
var CRMMessageDeleteLinkMixin = ( function($) {

    CRMMessageDeleteLinkMixin = function () {
        // empty constructor, cause it's mixin
    };

    CRMMessageDeleteLinkMixin.prototype.initMessageDeleteLink = function () {

        var that = this,
            $delete_link = that.$wrapper.find('.js-delete-message');

        $delete_link.on('click', function (event) {
            event.preventDefault();
            message_id = $(this).data('message-id') || ((that.message && that.message.id) ? that.message.id : null);
            $.crm.confirm.show({
                title: that.locales['delete_message'],
                text: that.locales['delete_message_text'],
                button: that.locales['delete'],
                onConfirm: deleteMessage
            });
        });

        function deleteMessage() {
            if (!message_id) {
                console.log(that.locales['message_not_found'] || "Message not found");
                showError(that.locales['message_not_found'] || "Message not found");
                return false;
            }

            var href = $.crm.app_url + "?module=message&action=delete",
                data = {id: message_id};

            var $loading = $('<span class="icon loading"><i class="fas fa-spinner wa-animation-spin"></i></span>');
            var $button = that.$button || $('.js-confirm-button');
            $loading.appendTo($button.parent());

            $button.attr("disabled", true);

            $.post(href, data, function (response) {
                if (response.status === "ok") {
                    $.crm.content.reload();
                    $('.dialog.c-message-show-body-dialog')?.data('dialog')?.close();
                } else {
                    console.log('Error saving Responsible contact classification: ' + arguments[2], arguments);
                    showError("Error saving Responsible contact classification: " + arguments[2]);
                }
            }, "json").always(function () {
                $button.attr("disabled", false);
                $loading.remove();
            });
        }

        function showError(error) {
            if (that.$errorsPlace) {
                var $error = $("<div class=\"errormsg\" />").text(error);
                that.$errorsPlace.append($error);
            }
        }
    };

    CRMMessageDeleteLinkMixin.mixInFor = function (Class) {
        Class.prototype = $.extend(Class.prototype, CRMMessageDeleteLinkMixin.prototype);
        return Class;
    };

    return CRMMessageDeleteLinkMixin;

})(jQuery);
