                var result;

                if (index === 1) {
                    result = [{
                        name: "верх. общее кол-во",
                        data: getPoints()
                    }, {
                        name: "верх. зависшие",
                        data: getPoints()
                    }];

                } else {
                    result = {
                        name: "низ. график времени",
                        data: getPoints()
                    }
                }

                return result;

